import React, { useState, useEffect } from 'react';
import { Card, Row, Col, Badge, ProgressBar, Alert, Accordion, Table, Collapse } from 'react-bootstrap';
import { 
  FileText, 
  Users, 
  Store, 
  CheckCircle, 
  XCircle, 
  AlertTriangle, 
  TrendingUp,
  AlertCircle,
  Clock,
  Target,
  ChevronDown,
  ChevronUp,
  Calendar,
  Download,
  Eye,
  FileCheck
} from 'lucide-react';
import { searchDocuments } from '../api';
import './ComplianceDashboard.css';

const ComplianceDashboard = () => {
  const [loading, setLoading] = useState(true);
  const [selectedStore, setSelectedStore] = useState(null);
  const [selectedEmployee, setSelectedEmployee] = useState(null);
  const [expandedStores, setExpandedStores] = useState({});
  const [showStoreDetails, setShowStoreDetails] = useState({});
  const [dashboardData, setDashboardData] = useState({
    totalDocuments: 0,
    validDocuments: 0,
    expiringDocuments: 0,
    expiredDocuments: 0,
    missingDocuments: 0,
    totalEmployees: 10,
    employeesWithCompleteDocuments: 0,
    employeesWithPendingDocuments: 0,
    storeWiseData: [],
    employeeWiseData: [],
    complianceRate: 0,
    allDocuments: []
  });

  // Employee-Store mapping
  const employeeStoreMapping = [
    { id: 'EMP001', name: 'Rajesh Kumar', store: 'Store 1' },
    { id: 'EMP002', name: 'Priya Singh', store: 'Store 2' },
    { id: 'EMP003', name: 'Amit Patel', store: 'Store 3' },
    { id: 'EMP004', name: 'Sneha Reddy', store: 'Store 4' },
    { id: 'EMP005', name: 'Vikram Sharma', store: 'Store 5' },
    { id: 'EMP006', name: 'Anita Desai', store: 'Store 6' },
    { id: 'EMP007', name: 'Rahul Mehta', store: 'Store 7' },
    { id: 'EMP008', name: 'Kavita Joshi', store: 'Store 8' },
    { id: 'EMP009', name: 'Suresh Nair', store: 'Store 9' },
    { id: 'EMP010', name: 'Meera Nair', store: 'Store 10' },
  ];

  // Mandatory document types
  const mandatoryDocuments = [
    'ID Proof',
    'Address Proof',
    'Educational Certificate',
    'Employment Contract'
  ];

  useEffect(() => {
    loadDashboardData();
  }, []);

  const getStatusColor = (expiryDate) => {
    if (!expiryDate) return 'valid';
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const expiry = new Date(expiryDate);
    expiry.setHours(0, 0, 0, 0);
    const daysUntilExpiry = Math.floor((expiry - today) / (1000 * 60 * 60 * 24));
    
    if (daysUntilExpiry <= 0) return 'expired';
    if (daysUntilExpiry <= 30) return 'expiring';
    return 'valid';
  };

  const formatDate = (dateString) => {
    if (!dateString) return 'N/A';
    const date = new Date(dateString);
    return date.toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' });
  };

  const getDaysRemaining = (expiryDate) => {
    if (!expiryDate) return null;
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const expiry = new Date(expiryDate);
    expiry.setHours(0, 0, 0, 0);
    const days = Math.floor((expiry - today) / (1000 * 60 * 60 * 24));
    return days;
  };

  const toggleStore = (storeName) => {
    setExpandedStores(prev => ({
      ...prev,
      [storeName]: !prev[storeName]
    }));
  };

  const loadDashboardData = async () => {
    setLoading(true);
    try {
      const response = await searchDocuments({});
      if (response.data && response.data.data) {
        const documents = response.data.data.map(doc => {
          const employee = employeeStoreMapping.find(emp => emp.id === doc.employeeId);
          return {
            ...doc,
            store: doc.store || (employee ? employee.store : 'Unknown'),
            employeeName: doc.employeeName || (employee ? employee.name : 'Unknown'),
            status: getStatusColor(doc.expiryDate)
          };
        });

        // Calculate statistics
        const totalDocuments = documents.length;
        const validDocuments = documents.filter(doc => doc.status === 'valid').length;
        const expiringDocuments = documents.filter(doc => doc.status === 'expiring').length;
        const expiredDocuments = documents.filter(doc => doc.status === 'expired').length;

        // Calculate employee-wise data
        const employeeDocCounts = {};
        documents.forEach(doc => {
          if (!employeeDocCounts[doc.employeeId]) {
            const emp = employeeStoreMapping.find(e => e.id === doc.employeeId);
            employeeDocCounts[doc.employeeId] = {
              employeeId: doc.employeeId,
              employeeName: emp ? emp.name : 'Unknown',
              store: emp ? emp.store : 'Unknown',
              totalDocs: 0,
              validDocs: 0,
              expiredDocs: 0,
              expiringDocs: 0,
              mandatoryDocs: [],
              missingMandatory: [],
              documents: []
            };
          }
          employeeDocCounts[doc.employeeId].totalDocs++;
          employeeDocCounts[doc.employeeId].documents.push(doc);
          if (doc.status === 'valid') employeeDocCounts[doc.employeeId].validDocs++;
          if (doc.status === 'expired') employeeDocCounts[doc.employeeId].expiredDocs++;
          if (doc.status === 'expiring') employeeDocCounts[doc.employeeId].expiringDocs++;
          
          if (mandatoryDocuments.includes(doc.documentType)) {
            employeeDocCounts[doc.employeeId].mandatoryDocs.push(doc.documentType);
          }
        });

        // Calculate missing mandatory documents
        let totalMissingDocs = 0;
        Object.keys(employeeDocCounts).forEach(empId => {
          const missing = mandatoryDocuments.filter(
            docType => !employeeDocCounts[empId].mandatoryDocs.includes(docType)
          );
          employeeDocCounts[empId].missingMandatory = missing;
          totalMissingDocs += missing.length;
        });

        // Add employees with no documents
        employeeStoreMapping.forEach(emp => {
          if (!employeeDocCounts[emp.id]) {
            employeeDocCounts[emp.id] = {
              employeeId: emp.id,
              employeeName: emp.name,
              store: emp.store,
              totalDocs: 0,
              validDocs: 0,
              expiredDocs: 0,
              expiringDocs: 0,
              mandatoryDocs: [],
              missingMandatory: mandatoryDocuments,
              documents: []
            };
            totalMissingDocs += mandatoryDocuments.length;
          }
        });

        const employeeWiseData = Object.values(employeeDocCounts);
        const employeesWithCompleteDocuments = employeeWiseData.filter(
          emp => emp.missingMandatory.length === 0 && emp.expiredDocs === 0
        ).length;
        const employeesWithPendingDocuments = employeeStoreMapping.length - employeesWithCompleteDocuments;

        // Calculate store-wise data
        const storeDocCounts = {};
        documents.forEach(doc => {
          if (!storeDocCounts[doc.store]) {
            storeDocCounts[doc.store] = {
              store: doc.store,
              totalDocs: 0,
              validDocs: 0,
              expiredDocs: 0,
              expiringDocs: 0,
              employees: new Set(),
              employeeList: []
            };
          }
          storeDocCounts[doc.store].totalDocs++;
          if (doc.status === 'valid') storeDocCounts[doc.store].validDocs++;
          if (doc.status === 'expired') storeDocCounts[doc.store].expiredDocs++;
          if (doc.status === 'expiring') storeDocCounts[doc.store].expiringDocs++;
          storeDocCounts[doc.store].employees.add(doc.employeeId);
        });

        // Add employee list to each store
        Object.keys(storeDocCounts).forEach(storeName => {
          storeDocCounts[storeName].employeeList = employeeWiseData.filter(
            emp => emp.store === storeName
          );
        });

        const storeWiseData = Object.values(storeDocCounts).map(store => ({
          ...store,
          employeeCount: store.employees.size,
          complianceRate: store.totalDocs > 0 
            ? Math.round((store.validDocs / store.totalDocs) * 100) 
            : 0
        }));

        // Sort by store name
        storeWiseData.sort((a, b) => {
          const numA = parseInt(a.store.replace('Store ', ''));
          const numB = parseInt(b.store.replace('Store ', ''));
          return numA - numB;
        });

        const overallCompliance = totalDocuments > 0 
          ? Math.round((validDocuments / totalDocuments) * 100) 
          : 0;

        setDashboardData({
          totalDocuments,
          validDocuments,
          expiringDocuments,
          expiredDocuments,
          missingDocuments: totalMissingDocs,
          totalEmployees: employeeStoreMapping.length,
          employeesWithCompleteDocuments,
          employeesWithPendingDocuments,
          storeWiseData,
          employeeWiseData,
          complianceRate: overallCompliance,
          allDocuments: documents
        });
      }
    } catch (error) {
      console.error('Error loading dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="d-flex justify-content-center align-items-center" style={{ minHeight: '400px' }}>
        <div className="text-center">
          <div className="spinner-border text-primary" role="status">
            <span className="visually-hidden">Loading...</span>
          </div>
          <p className="mt-3 text-muted">Loading compliance data...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="compliance-dashboard">
      {/* Header */}
      <Card className="border-0 shadow-sm mb-4 bg-gradient-primary text-white">
        <Card.Body className="p-4">
          <div className="d-flex justify-content-between align-items-center">
            <div>
              <h3 className="mb-1">
                <Target className="me-2" size={28} />
                Compliance Dashboard
              </h3>
              <p className="mb-0 opacity-75">Real-time document compliance tracking</p>
            </div>
            <div className="text-end">
              <div className="h2 mb-0 fw-bold">{dashboardData.complianceRate}%</div>
              <small className="opacity-75">Overall Compliance</small>
            </div>
          </div>
        </Card.Body>
      </Card>

      {/* Statistics Cards */}
      <Row className="mb-4">
        <Col md={3} sm={6} className="mb-3">
          <Card className="border-0 shadow-sm stats-card h-100">
            <Card.Body>
              <div className="d-flex justify-content-between align-items-center">
                <div>
                  <p className="text-muted mb-1 small">Total Documents</p>
                  <h3 className="mb-0 fw-bold">{dashboardData.totalDocuments}</h3>
                </div>
                <div className="stats-icon bg-primary">
                  <FileText size={24} />
                </div>
              </div>
            </Card.Body>
          </Card>
        </Col>
        <Col md={3} sm={6} className="mb-3">
          <Card className="border-0 shadow-sm stats-card h-100">
            <Card.Body>
              <div className="d-flex justify-content-between align-items-center">
                <div>
                  <p className="text-muted mb-1 small">Valid Documents</p>
                  <h3 className="mb-0 fw-bold text-success">{dashboardData.validDocuments}</h3>
                </div>
                <div className="stats-icon bg-success">
                  <CheckCircle size={24} />
                </div>
              </div>
            </Card.Body>
          </Card>
        </Col>
        <Col md={3} sm={6} className="mb-3">
          <Card className="border-0 shadow-sm stats-card h-100">
            <Card.Body>
              <div className="d-flex justify-content-between align-items-center">
                <div>
                  <p className="text-muted mb-1 small">Expiring Soon</p>
                  <h3 className="mb-0 fw-bold text-warning">{dashboardData.expiringDocuments}</h3>
                </div>
                <div className="stats-icon bg-warning">
                  <Clock size={24} />
                </div>
              </div>
            </Card.Body>
          </Card>
        </Col>
        <Col md={3} sm={6} className="mb-3">
          <Card className="border-0 shadow-sm stats-card h-100">
            <Card.Body>
              <div className="d-flex justify-content-between align-items-center">
                <div>
                  <p className="text-muted mb-1 small">Expired/Missing</p>
                  <h3 className="mb-0 fw-bold text-danger">
                    {dashboardData.expiredDocuments + dashboardData.missingDocuments}
                  </h3>
                </div>
                <div className="stats-icon bg-danger">
                  <AlertTriangle size={24} />
                </div>
              </div>
            </Card.Body>
          </Card>
        </Col>
      </Row>

      {/* Store-wise Document Summary with Collapsible Sections */}
      <Card className="border-0 shadow-sm mb-4">
        <Card.Header className="bg-white border-bottom py-3">
          <div className="d-flex justify-content-between align-items-center">
            <div>
              <h5 className="mb-1">
                <Store className="me-2" size={20} />
                Store-wise Document Summary
              </h5>
              <small className="text-muted">Click on any store to view employee details</small>
            </div>
          </div>
        </Card.Header>
        <Card.Body className="p-0">
          {dashboardData.storeWiseData.map((store, idx) => (
            <div key={idx} className="store-accordion-item">
              <div 
                className="store-header-clickable"
                onClick={() => toggleStore(store.store)}
              >
                <div className="d-flex align-items-center justify-content-between p-3 border-bottom">
                  <div className="d-flex align-items-center flex-grow-1">
                    <div className="me-3">
                      {expandedStores[store.store] ? (
                        <ChevronUp size={20} className="text-primary" />
                      ) : (
                        <ChevronDown size={20} className="text-muted" />
                      )}
                    </div>
                    <div className="flex-grow-1">
                      <h6 className="mb-1 fw-bold">{store.store}</h6>
                      <div className="d-flex gap-2 flex-wrap">
                        <Badge bg="secondary" className="badge-sm">
                          <Users size={12} className="me-1" />
                          {store.employeeCount} Employees
                        </Badge>
                        <Badge bg="light" text="dark" className="badge-sm">
                          <FileText size={12} className="me-1" />
                          {store.totalDocs} Documents
                        </Badge>
                      </div>
                    </div>
                  </div>
                  <div className="d-flex align-items-center gap-3">
                    <div className="text-end me-3 d-none d-md-block">
                      <div className="d-flex gap-2 mb-2">
                        <Badge bg="success">{store.validDocs} Valid</Badge>
                        {store.expiringDocs > 0 && <Badge bg="warning">{store.expiringDocs} Expiring</Badge>}
                        {store.expiredDocs > 0 && <Badge bg="danger">{store.expiredDocs} Expired</Badge>}
                      </div>
                      <ProgressBar 
                        now={store.complianceRate} 
                        variant={store.complianceRate >= 80 ? 'success' : store.complianceRate >= 50 ? 'warning' : 'danger'}
                        style={{ width: '150px', height: '8px' }}
                      />
                    </div>
                    <div className="compliance-badge-circular">
                      <div className={`circular-progress ${
                        store.complianceRate >= 80 ? 'progress-success' : 
                        store.complianceRate >= 50 ? 'progress-warning' : 'progress-danger'
                      }`}>
                        <span className="progress-value">{store.complianceRate}%</span>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              <Collapse in={expandedStores[store.store]}>
                <div className="store-employees-container">
                  <div className="p-3 bg-light">
                    <h6 className="mb-3 text-muted">
                      <Users size={16} className="me-2" />
                      Employees in {store.store}
                    </h6>
                    <Row>
                      {store.employeeList.map((emp, empIdx) => {
                        const isCompliant = emp.missingMandatory.length === 0 && emp.expiredDocs === 0;
                        return (
                          <Col md={6} lg={4} key={empIdx} className="mb-3">
                            <Card 
                              className={`employee-card-mini h-100 ${!isCompliant ? 'border-warning' : 'border-success'}`}
                              onClick={() => setSelectedEmployee(emp)}
                              style={{ cursor: 'pointer' }}
                            >
                              <Card.Body className="p-3">
                                <div className="d-flex justify-content-between align-items-start mb-2">
                                  <div className="flex-grow-1">
                                    <h6 className="mb-0 fw-bold">{emp.employeeName}</h6>
                                    <small className="text-muted">{emp.employeeId}</small>
                                  </div>
                                  {isCompliant ? (
                                    <CheckCircle size={20} className="text-success" />
                                  ) : (
                                    <AlertTriangle size={20} className="text-warning" />
                                  )}
                                </div>
                                <div className="employee-mini-stats">
                                  <div className="d-flex justify-content-between text-sm mb-1">
                                    <span className="text-muted">Documents:</span>
                                    <span className="fw-bold">{emp.totalDocs}</span>
                                  </div>
                                  <div className="d-flex gap-1">
                                    {emp.validDocs > 0 && (
                                      <Badge bg="success" className="flex-fill text-center py-1 badge-xs">
                                        {emp.validDocs} Valid
                                      </Badge>
                                    )}
                                    {emp.expiringDocs > 0 && (
                                      <Badge bg="warning" className="flex-fill text-center py-1 badge-xs">
                                        {emp.expiringDocs} Soon
                                      </Badge>
                                    )}
                                    {emp.expiredDocs > 0 && (
                                      <Badge bg="danger" className="flex-fill text-center py-1 badge-xs">
                                        {emp.expiredDocs} Expired
                                      </Badge>
                                    )}
                                    {emp.missingMandatory.length > 0 && (
                                      <Badge bg="danger" className="flex-fill text-center py-1 badge-xs">
                                        {emp.missingMandatory.length} Missing
                                      </Badge>
                                    )}
                                  </div>
                                </div>
                              </Card.Body>
                            </Card>
                          </Col>
                        );
                      })}
                    </Row>
                  </div>
                </div>
              </Collapse>
            </div>
          ))}
        </Card.Body>
      </Card>

      {/* Employee Detail Modal */}
      {selectedEmployee && (
        <div className="employee-detail-overlay" onClick={() => setSelectedEmployee(null)}>
          <Card 
            className="employee-detail-modal border-0 shadow-lg"
            onClick={(e) => e.stopPropagation()}
          >
            <Card.Header className="bg-gradient-primary text-white">
              <div className="d-flex justify-content-between align-items-center">
                <div>
                  <h5 className="mb-1">
                    <Users size={20} className="me-2" />
                    {selectedEmployee.employeeName}
                  </h5>
                  <small className="opacity-75">
                    {selectedEmployee.employeeId} • {selectedEmployee.store}
                  </small>
                </div>
                <button 
                  className="btn btn-sm btn-light"
                  onClick={() => setSelectedEmployee(null)}
                >
                  ✕ Close
                </button>
              </div>
            </Card.Header>
            <Card.Body>
              {/* Summary Stats */}
              <Row className="mb-4">
                <Col xs={6} md={3}>
                  <div className="stat-box text-center p-3 bg-light rounded">
                    <FileText size={24} className="text-primary mb-2" />
                    <div className="h4 mb-0">{selectedEmployee.totalDocs}</div>
                    <small className="text-muted">Total</small>
                  </div>
                </Col>
                <Col xs={6} md={3}>
                  <div className="stat-box text-center p-3 bg-light rounded">
                    <CheckCircle size={24} className="text-success mb-2" />
                    <div className="h4 mb-0">{selectedEmployee.validDocs}</div>
                    <small className="text-muted">Valid</small>
                  </div>
                </Col>
                <Col xs={6} md={3}>
                  <div className="stat-box text-center p-3 bg-light rounded">
                    <Clock size={24} className="text-warning mb-2" />
                    <div className="h4 mb-0">{selectedEmployee.expiringDocs}</div>
                    <small className="text-muted">Expiring</small>
                  </div>
                </Col>
                <Col xs={6} md={3}>
                  <div className="stat-box text-center p-3 bg-light rounded">
                    <XCircle size={24} className="text-danger mb-2" />
                    <div className="h4 mb-0">{selectedEmployee.expiredDocs}</div>
                    <small className="text-muted">Expired</small>
                  </div>
                </Col>
              </Row>

              {/* Missing Documents Alert */}
              {selectedEmployee.missingMandatory.length > 0 && (
                <Alert variant="danger" className="mb-3">
                  <div className="d-flex align-items-start">
                    <AlertTriangle className="me-2 flex-shrink-0" size={20} />
                    <div className="flex-grow-1">
                      <strong>Missing Mandatory Documents ({selectedEmployee.missingMandatory.length})</strong>
                      <ul className="mb-0 mt-2">
                        {selectedEmployee.missingMandatory.map((doc, i) => (
                          <li key={i}>{doc}</li>
                        ))}
                      </ul>
                    </div>
                  </div>
                </Alert>
              )}

              {/* Expired Documents Warning */}
              {selectedEmployee.expiredDocs > 0 && (
                <Alert variant="warning" className="mb-3">
                  <div className="d-flex align-items-start">
                    <XCircle className="me-2 flex-shrink-0" size={20} />
                    <div>
                      <strong>Action Required!</strong>
                      <p className="mb-0 mt-1">
                        {selectedEmployee.expiredDocs} document(s) have expired and need immediate renewal.
                      </p>
                    </div>
                  </div>
                </Alert>
              )}

              {/* Success Message */}
              {selectedEmployee.missingMandatory.length === 0 && selectedEmployee.expiredDocs === 0 && selectedEmployee.totalDocs > 0 && (
                <Alert variant="success" className="mb-3">
                  <div className="d-flex align-items-center">
                    <CheckCircle className="me-2" size={20} />
                    <strong>All Clear!</strong> All documents are valid and up-to-date.
                  </div>
                </Alert>
              )}

              {/* Document List */}
              <div className="document-list-section">
                <h6 className="mb-3 d-flex align-items-center">
                  <FileCheck size={18} className="me-2 text-primary" />
                  Uploaded Documents ({selectedEmployee.documents.length})
                </h6>
                
                {selectedEmployee.documents.length > 0 ? (
                  <div className="table-responsive">
                    <Table hover className="document-table mb-0">
                      <thead className="bg-light">
                        <tr>
                          <th>Document Type</th>
                          <th>Document Name</th>
                          <th>Issue Date</th>
                          <th>Expiry Date</th>
                          <th>Status</th>
                          <th>Days Left</th>
                        </tr>
                      </thead>
                      <tbody>
                        {selectedEmployee.documents.map((doc, idx) => {
                          const daysLeft = getDaysRemaining(doc.expiryDate);
                          return (
                            <tr key={idx} className={`document-row status-${doc.status}`}>
                              <td className="fw-semibold">{doc.documentType}</td>
                              <td>
                                <div className="d-flex align-items-center">
                                  <FileText size={16} className="me-2 text-muted" />
                                  <span className="text-truncate" title={doc.documentName}>
                                    {doc.documentName || 'Unnamed Document'}
                                  </span>
                                </div>
                              </td>
                              <td>
                                <div className="d-flex align-items-center text-muted">
                                  <Calendar size={14} className="me-1" />
                                  {formatDate(doc.issueDate)}
                                </div>
                              </td>
                              <td>
                                <div className="d-flex align-items-center text-muted">
                                  <Calendar size={14} className="me-1" />
                                  {formatDate(doc.expiryDate)}
                                </div>
                              </td>
                              <td>
                                {doc.status === 'valid' && (
                                  <Badge bg="success" className="badge-pill">
                                    <CheckCircle size={12} className="me-1" />
                                    Valid
                                  </Badge>
                                )}
                                {doc.status === 'expiring' && (
                                  <Badge bg="warning" className="badge-pill">
                                    <Clock size={12} className="me-1" />
                                    Expiring Soon
                                  </Badge>
                                )}
                                {doc.status === 'expired' && (
                                  <Badge bg="danger" className="badge-pill">
                                    <XCircle size={12} className="me-1" />
                                    Expired
                                  </Badge>
                                )}
                              </td>
                              <td>
                                {daysLeft !== null ? (
                                  <span className={`fw-semibold ${
                                    daysLeft < 0 ? 'text-danger' : 
                                    daysLeft <= 30 ? 'text-warning' : 'text-success'
                                  }`}>
                                    {daysLeft < 0 ? `${Math.abs(daysLeft)} days ago` : `${daysLeft} days`}
                                  </span>
                                ) : (
                                  <span className="text-muted">-</span>
                                )}
                              </td>
                            </tr>
                          );
                        })}
                      </tbody>
                    </Table>
                  </div>
                ) : (
                  <div className="text-center py-4 text-muted">
                    <FileText size={48} className="mb-2 opacity-50" />
                    <p className="mb-0">No documents uploaded yet</p>
                  </div>
                )}
              </div>

              {/* Last Updated Info */}
              <div className="mt-4 pt-3 border-top">
                <small className="text-muted">
                  <Clock size={14} className="me-1" />
                  Last updated: {formatDate(selectedEmployee.documents[0]?.updatedAt || new Date())}
                </small>
              </div>
            </Card.Body>
          </Card>
        </div>
      )}
    </div>
  );
};

export default ComplianceDashboard;
